    // Zero increment must be rejected on both sides
    assert!(
        interp_src.contains("*increment == 0"),
        "NET7-10d: Interpreter must reject zero increment"
    );
    assert!(
        native_src.contains("value == 0"),
        "NET7-10d: Native must reject zero increment"
    );
